import React, { useEffect, useState } from "react";
import EditorShell from "./shared/EditorShell";
import BaseQuestionFields from "./shared/BaseQuestionFields";

export default function QueFormLoginPageEditor({ data, onSave, onClose, saveRef, isDefaultLanguage = true }) {
  const [item, setItem] = useState(
    data || { name: "", text: "", required: false, validationMessage: "", horizontalLine: false }
  );
  
  useEffect(() => { 
    if (data) setItem(prev => ({ ...prev, ...data })); 
  }, [data]);
  
  const handleSave = () => { 
    onSave?.(item); 

  };
  

  
  return (
    <EditorShell onSave={handleSave} onClose={onClose} saveRef={saveRef}>
      <BaseQuestionFields
        item={item}
        onChange={setItem}
        disableText={false}
        isDefaultLanguage={isDefaultLanguage}
        overrideHorizontalLineDisabled={false}
        suppressValidation={true}
        questionType="FormLoginPage"
      />
    </EditorShell>
  );
}



